CREATE MEMORY TABLE "PUBLIC"."PERSONAL_RECORDS"(
    "BODYWEIGHT_KG" NUMERIC(6, 2),
    "LIFT_DATE" DATE NOT NULL,
    "MILESTONE" BOOLEAN NOT NULL,
    "REPS" INTEGER NOT NULL,
    "RPE" INTEGER,
    "SETS" INTEGER,
    "WEIGHT_KG" NUMERIC(6, 2) NOT NULL,
    "ADDED_BY_ID" BIGINT,
    "CREATED_AT" TIMESTAMP(6),
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 13) NOT NULL,
    "UPDATED_AT" TIMESTAMP(6),
    "GYM_LOCATION" CHARACTER VARYING(100),
    "EQUIPMENT" CHARACTER VARYING(150),
    "NOTES" CHARACTER VARYING(2000),
    "LIFT_TYPE" ENUM('BARBELL_ROW', 'BENCH_PRESS', 'CLEAN_AND_JERK', 'DEADLIFT', 'FRONT_SQUAT', 'HIP_THRUST', 'OVERHEAD_PRESS', 'PULL_UP', 'SNATCH', 'SQUAT') NOT NULL,
    "MUSCLE_GROUP" ENUM('ARMS', 'BACK', 'CHEST', 'CORE', 'FULL_BODY', 'LEGS', 'SHOULDERS') NOT NULL
);       
